Une **fonction** retourne une valeur et s'utilise dans un `SELECT` :

```sql
-- Créer une fonction
CREATE FUNCTION salaire_annuel(sal REAL) RETURNS REAL AS $$
  SELECT sal * 12;
$$ LANGUAGE SQL;

-- Utilisation
SELECT name, salaire_annuel(salary) AS annuel FROM employees;

-- Fonction qui retourne une table
CREATE FUNCTION employes_dept(dept TEXT)
RETURNS TABLE(name TEXT, salary REAL) AS $$
  SELECT name, salary FROM employees WHERE department = dept;
$$ LANGUAGE SQL;

SELECT * FROM employes_dept('IT');
```
